import { useState } from "react";
import { getWeather } from "../services/weatherAPI";

function Chatbot() {

    const [question, setQuestion] = useState("");
    const [response, setResponse] = useState("");

    const handleSend = async () => {

        // Extract city name (first word)
        const city = question.split(" ")[0];

        const weather = await getWeather(city);

        if (weather) {

            setResponse(
                `Temperature in ${city} is ${weather.temperature}°C and wind speed is ${weather.windspeed} km/h`
            );

        } else {

            setResponse("City not found");

        }

    };

    return (
        <div className="page">

            <h1>AI Climate Chatbot</h1>

            <input
                type="text"
                placeholder="Ask climate question"
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
            />

            <button onClick={handleSend}>Send</button>

            <h3>{response}</h3>

        </div>
    );
}

export default Chatbot;
